form:Form.form:Scripts:
		function Aceptar()
{               
 	if (Ctrl("list2").TotalRowsCount()==0)
 	{             
 		alert("No hay legajos filtrados.");
 		return false;
 	}

 	Ctrl('legajos').DelAllRow();
 	for (key in arrB) Ctrl('legajos').AddRow().SetAttr('id', key.substr(1));

	Ctrl("main").DoEvent("OK");
}
